import React from 'react';
import ReactDOM from 'react-dom';
import * as serviceWorker from './serviceWorker';
import { BrowserRouter as Router, Switch, Route, Link, useRouteMatch, useParams } from "react-router-dom";

import App from './App';
import Notfound from './Component/NotFound'
import About from './Component/About';
import WorkExperience from './Component/WorkExperience';
import Education from './Component/Education';
import Certification from './Component/Certification';
import Skills from './Component/Skills';
import Awards from './Component/Awards';
import Interests from './Component/Interests';
import Blogs from './Component/Blogs';
import Github from './Component/GitHub'
import Navigation from './Component/Navigation'

const BaseName = "portfolio";
const routing = (<Router basename={BaseName}>
    <Navigation></Navigation>
    <Route path={BaseName + "/about"}>
        <About></About>
    </Route>
    <Route path={BaseName + "/experience"}>
        <WorkExperience></WorkExperience>
    </Route>
    <Route path={BaseName + "/education"}>
        <Education></Education>
    </Route>
    <Route path={BaseName + "/skills"}>
        <Skills></Skills>
    </Route>
    <Route path={BaseName + "/certification"}>
        <Certification></Certification>
    </Route>
    <Route path={BaseName + "/awards"}>
        <Awards></Awards>
    </Route>
    <Route path={BaseName + "/interests"}>
        <Interests></Interests>
    </Route>
    <Route path={BaseName + "/github"}>
        <Github></Github>
    </Route>
    <Route path={BaseName + "/blogs"}>
        <Blogs></Blogs>
    </Route>
    <Route exact path={BaseName + "/"}>
        <About></About>
    </Route>
</Router>);



ReactDOM.render(routing, document.getElementById('root'));
// If you want your app to work offline and load faster, you can change
// unregister() to register() below. Note this comes with some pitfalls.
// Learn more about service workers: https://bit.ly/CRA-PWA
serviceWorker.unregister();
